import React from 'react';
import { FiBriefcase, FiHome, FiMail, FiMoon, FiSun, FiUser } from 'react-icons/fi';
import { useTheme } from '../context/ThemeContext';

const Nav = ({ toggleTheme }) => {
  const { theme } = useTheme();
  const navLogo = '';

  return (
    <nav className="nav">
      <div className="container">
        <a className="nav-brand" href="#home" aria-label="Home">
          {navLogo ? (
            <img src={navLogo} alt="John Doe logo" />
          ) : (
            <span className="nav-brand-placeholder">JD</span>
          )}
          <span className="nav-brand-text">John Doe</span>
        </a>
        <ul className="nav-list">
          <li><a href="#home"><FiHome aria-hidden="true" /> Home</a></li>
          <li><a href="#about"><FiUser aria-hidden="true" /> About</a></li>
          <li><a href="#experience"><FiBriefcase aria-hidden="true" /> Experience</a></li>
          <li><a href="#contact"><FiMail aria-hidden="true" /> Contact</a></li>
        </ul>
        <button
          className="theme-toggle"
          onClick={toggleTheme}
          aria-label="Toggle theme"
          title="Toggle theme"
        >
          {theme === 'light' ? <FiMoon aria-hidden="true" /> : <FiSun aria-hidden="true" />}
        </button>
      </div>
    </nav>
  );
};

export default Nav;
